const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [a, b, c, d] = input.split(' ').map(Number);
    const arr = [a, b, c, d];
    arr.sort((a, b) => a - b);
    console.log(arr[0], arr[1], arr[2]);
});
